import{_ as e,c as a,a1 as i,o}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Viewing, Enabling and Clearing Audit Policies using Auditpol","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md"}'),d={name:"categories/ethical-hacking-labs/5-system-hacking/11-Auditpol.md"};function c(s,t,r,l,n,u){return o(),a("div",null,t[0]||(t[0]=[i('<h1 id="viewing-enabling-and-clearing-audit-policies-using-auditpol" tabindex="-1">Viewing, Enabling and Clearing Audit Policies using Auditpol <a class="header-anchor" href="#viewing-enabling-and-clearing-audit-policies-using-auditpol" aria-label="Permalink to &quot;Viewing, Enabling and Clearing Audit Policies using Auditpol&quot;">​</a></h1><p>Auditpol is a command in Windows Server 2016, 2012 and 2008, and is required for querying or configuring audit policy at the subcategory level.</p><p>Auditpol displays the information on the performance and functions to manipulate audit policies.</p><p><strong>Microsoft Documentation</strong>: <a href="https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/auditpol" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/windows-server/administration/windows-commands/auditpol</a></p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>How to set the Audit Policies</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows Server 2016/2012 virtual machine.</li></ul><hr><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/aa898df1242308b3886dbf6d8c252a5dcb30089d/auditpol-syntax.png" alt="syntax"></p><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/set</code></td><td>Sets the audit policy.</td></tr><tr><td><code>/get</code></td><td>Displays the current audit policy.</td></tr><tr><td><code>/backup</code></td><td>Saves the audit policy to a file.</td></tr><tr><td><code>/list</code></td><td>Displays selectable policy elements.</td></tr><tr><td><code>/restore</code></td><td>Restores the audit policy from a file that was previously created by using auditpol/backup.</td></tr><tr><td><code>/remove</code></td><td>Removes all per-user audit policy settings and disables all system audit policy settings.</td></tr><tr><td><code>/clear</code></td><td>Clears the audit policy.</td></tr><tr><td><code>/resourceSACL</code></td><td>Configures global resource system access control lists (SALCs).</td></tr></tbody></table><h3 id="to-view-all-the-audit-policies" tabindex="-1">To view all the audit policies: <a class="header-anchor" href="#to-view-all-the-audit-policies" aria-label="Permalink to &quot;To view all the audit policies:&quot;">​</a></h3><p>Launch <strong>Command Prompt</strong> from the Windows Server and type: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/aa898df1242308b3886dbf6d8c252a5dcb30089d/auditpol-1.png" alt="auditpol-category"></p><p>To <strong>enable</strong> the audit policies, type: <code>auditpol /set /category:&quot;system&quot;, &quot;account logon&quot; /success:enable /failure:enable</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fdf96591f9b797cf067e6118b0cc35caf00f6eb7/auditpol-2.png" alt="auditpol-enable"></p><p>To check whether audit policies are enable, type: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8fe2d30ad3c2300f259ad9d4a56ccba2ded7d838/auditpol-3.png" alt="auditpol-success-failure"></p><p>To <strong>clear</strong> the audit policies, type: <code>auditpol /clear /y</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/75ff457ae9710b831a2e867d9acf5e0947bd3958/auditpol-4.png" alt="auditclear"></p><p>To check wheter audit policies cleared, type: <code>auditpol /get /category:*</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/39e8b217d60a368deaa7d384a43722747e643744/auditpol-5.png" alt="audit-check-clear"></p>',22)]))}const h=e(d,[["render",c]]);export{g as __pageData,h as default};
